// Secure salt generation using OpenSSL CSPRNG
bool generateSalt(unsigned char* salt, size_t length) {
    // Use OpenSSL's cryptographically secure random generator\n    if (RAND_bytes(salt, length) != 1) {\n        return false;\n    }\n    return true;\n}\n\n// Secure password hashing using PBKDF2-HMAC-SHA256\nstd::string hashPassword(const std::string& password, const unsigned char* salt, size_t saltLen) {\n    const int iterations = 210000; // Minimum required iterations\n    const int keyLength = 32;\n    unsigned char hash[keyLength];\n    \n    // Use PBKDF2 with SHA-256\n    if (PKCS5_PBKDF2_HMAC(\n        password.c_str(), password.length(),\n        salt, saltLen,\n        iterations,\n        EVP_sha256(),\n        keyLength,\n        hash\n    ) != 1) {\n        return "";\n    }\n    \n    // Base64 encode the hash\n    BIO* bio = BIO_new(BIO_s_mem());\n    BIO* b64 = BIO_new(BIO_f_base64());\n    BIO_set_flags(b64, BIO_FLAGS_BASE64_NO_NL);\n    bio = BIO_push(b64, bio);\n    BIO_write(bio, hash, keyLength);\n    BIO_flush(bio);\n    \n    BUF_MEM* bufferPtr;\n    BIO_get_mem_ptr(bio, &bufferPtr);\n    std::string result(bufferPtr->data, bufferPtr->length);\n    \n    BIO_free_all(bio);\n    \n    // Clear sensitive data from memory\n    OPENSSL_cleanse(hash, keyLength);\n    \n    return result;\n}\n\n// Input validation to prevent injection attacks\nbool validateInput(const std::string& username, const std::string& password) {\n    // Check for empty inputs\n    if (username.empty() || password.empty()) {\n        return false;\n    }\n    \n    // Length validation\n    if (username.length() > 255 || password.length() > 1024) {\n        return false;\n    }\n    \n    // Username format validation - alphanumeric and underscore only\n    std::regex usernamePattern("^[a-zA-Z0-9_]{3,255}$");\n    if (!std::regex_match(username, usernamePattern)) {\n        return false;\n    }\n    \n    return true;\n}\n\n// Constant-time comparison to prevent timing attacks\nbool secureCompare(const std::string& a, const std::string& b) {\n    if (a.length() != b.length()) {\n        return false;\n    }\n    return CRYPTO_memcmp(a.c_str(), b.c_str(), a.length()) == 0;\n}\n\n// Secure login function with parameterized queries\nstd::string login(const std::string& username, const std::string& password) {\n    // Input validation\n    if (!validateInput(username, password)) {\n        return "redirect:/login?error=invalid";\n    }\n    \n    MYSQL* conn = nullptr;\n    MYSQL_STMT* stmt = nullptr;\n    MYSQL_BIND bind[1];\n    MYSQL_BIND result[2];\n    \n    try {\n        // Initialize MySQL connection\n        conn = mysql_init(nullptr);\n        if (!conn) {\n            return "redirect:/login?error=system";\n        }\n        \n        // Enable TLS for secure connection\n        mysql_ssl_set(conn, nullptr, nullptr, nullptr, nullptr, nullptr);\n        unsigned int ssl_mode = SSL_MODE_REQUIRED;\n        mysql_options(conn, MYSQL_OPT_SSL_MODE, &ssl_mode);\n        \n        // Get credentials from environment variables\n        const char* host = std::getenv("DB_HOST");\n        const char* user = std::getenv("DB_USER");\n        const char* db_pass = std::getenv("DB_PASSWORD");\n        const char* database = std::getenv("DB_NAME");\n        \n        // Connect to database\n        if (!mysql_real_connect(conn, host, user, db_pass, database, 0, nullptr, 0)) {\n            mysql_close(conn);\n            return "redirect:/login?error=system";\n        }\n        \n        // Prepare parameterized statement to prevent SQL injection\n        const char* query = "SELECT password_hash, salt FROM users WHERE username = ? AND account_locked = FALSE LIMIT 1";\n        stmt = mysql_stmt_init(conn);\n        if (!stmt || mysql_stmt_prepare(stmt, query, std::strlen(query)) != 0) {\n            if (stmt) mysql_stmt_close(stmt);\n            mysql_close(conn);\n            return "redirect:/login?error=system";\n        }\n        \n        // Bind input parameter\n        std::memset(bind, 0, sizeof(bind));\n        unsigned long username_length = username.length();\n        bind[0].buffer_type = MYSQL_TYPE_STRING;\n        bind[0].buffer = const_cast<char*>(username.c_str());\n        bind[0].buffer_length = username.length();\n        bind[0].length = &username_length;\n        \n        if (mysql_stmt_bind_param(stmt, bind) != 0) {\n            mysql_stmt_close(stmt);\n            mysql_close(conn);\n            return "redirect:/login?error=system";\n        }\n        \n        // Execute query\n        if (mysql_stmt_execute(stmt) != 0) {\n            mysql_stmt_close(stmt);\n            mysql_close(conn);\n            return "redirect:/login?error=system";\n        }\n        \n        // Bind result parameters\n        char stored_hash[256];\n        char salt_str[256];\n        unsigned long hash_length, salt_length;\n        my_bool is_null[2];\n        \n        std::memset(result, 0, sizeof(result));\n        result[0].buffer_type = MYSQL_TYPE_STRING;\n        result[0].buffer = stored_hash;\n        result[0].buffer_length = sizeof(stored_hash);\n        result[0].length = &hash_length;\n        result[0].is_null = &is_null[0];\n        \n        result[1].buffer_type = MYSQL_TYPE_STRING;\n        result[1].buffer = salt_str;\n        result[1].buffer_length = sizeof(salt_str);\n        result[1].length = &salt_length;\n        result[1].is_null = &is_null[1];\n        \n        if (mysql_stmt_bind_result(stmt, result) != 0) {\n            mysql_stmt_close(stmt);\n            mysql_close(conn);\n            return "redirect:/login?error=system";\n        }\n        \n        // Fetch result\n        int fetch_result = mysql_stmt_fetch(stmt);\n        \n        if (fetch_result == 0) {\n            // User found - verify password\n            stored_hash[hash_length] = '\\0';\n            salt_str[salt_length] = '\\0';\n            \n            // Decode base64 salt (simplified - assumes base64 decoded salt)\n            std::string computedHash = hashPassword(password, \n                reinterpret_cast<unsigned char*>(salt_str), salt_length);\n            \n            // Constant-time comparison\n            if (secureCompare(computedHash, std::string(stored_hash))) {\n                mysql_stmt_close(stmt);\n                mysql_close(conn);\n                return "redirect:/dashboard";\n            } else {\n                mysql_stmt_close(stmt);\n                mysql_close(conn);\n                return "redirect:/login?error=invalid";\n            }\n        } else {\n            // User not found - generic error to prevent enumeration\n            mysql_stmt_close(stmt);\n            mysql_close(conn);\n            return "redirect:/login?error=invalid";\n        }\n        \n    } catch (...) {\n        if (stmt) mysql_stmt_close(stmt);\n        if (conn) mysql_close(conn);\n        return "redirect:/login?error=system";\n    }\n}\n\nint main() {\n    // Test cases\n    std::cout << "Test 1: " << login("validuser", "ValidPass123!") << std::endl;\n    std::cout << "Test 2: " << login("validuser", "wrongpassword") << std::endl;\n    std::cout << "Test 3: " << login("nonexistent", "password") << std::endl;\n    std::cout << "Test 4: " << login("admin' OR '1'='1", "password") << std::endl;\n    std::cout << "Test 5: " << login("", "") << std::endl;
    
    return 0;
}
